9007 llvm::canConvertToMinOrMaxIntrinsic(ArrayRef<Value *> VL) {
9008   // Check if VL contains select instructions that can be folded into a min/max
9009   // vector intrinsic and return the intrinsic if it is possible.
9010   // TODO: Support floating point min/max.
9011   bool AllCmpSingleUse = true;
9012   SelectPatternResult SelectPattern;
9013   SelectPattern.Flavor = SPF_UNKNOWN;
9014   if (all_of(VL, [&SelectPattern, &AllCmpSingleUse](Value *I) {
9015         Value *LHS, *RHS;
9016         auto CurrentPattern = matchSelectPattern(I, LHS, RHS);
9017         if (!SelectPatternResult::isMinOrMax(CurrentPattern.Flavor))
9018           return false;
9019         if (SelectPattern.Flavor != SPF_UNKNOWN &&
9020             SelectPattern.Flavor != CurrentPattern.Flavor)
9021           return false;
9022         SelectPattern = CurrentPattern;
9023         AllCmpSingleUse &=
9024             match(I, m_Select(m_OneUse(m_Value()), m_Value(), m_Value()));
9025         return true;
9026       })) {
9027     switch (SelectPattern.Flavor) {
9028     case SPF_SMIN:
9029       return {Intrinsic::smin, AllCmpSingleUse};
9030     case SPF_UMIN:
9031       return {Intrinsic::umin, AllCmpSingleUse};
9032     case SPF_SMAX:
9033       return {Intrinsic::smax, AllCmpSingleUse};
9034     case SPF_UMAX:
9035       return {Intrinsic::umax, AllCmpSingleUse};
9036     case SPF_FMAXNUM:
9037       return {Intrinsic::maxnum, AllCmpSingleUse};
9038     case SPF_FMINNUM:
9039       return {Intrinsic::minnum, AllCmpSingleUse};
9040     default:
9041       llvm_unreachable("unexpected select pattern flavor");
9042     }
9043   }
9044   return {Intrinsic::not_intrinsic, false};
