9106 bool llvm::matchSimpleRecurrence(const BinaryOperator *I, PHINode *&P,
9107                                  Value *&Start, Value *&Step) {
9108   BinaryOperator *BO = nullptr;
9109   P = dyn_cast<PHINode>(I->getOperand(0));
